var reorderList = function(head) {
    if (!head || !head.next) return;
    let slow = head, fast = head;
    while (fast.next && fast.next.next) {
        slow = slow.next;
        fast = fast.next.next;
    }
    let second = slow.next;
    slow.next = null;
    let prev = null;
    while (second) {
        const nxt = second.next;
        second.next = prev;
        prev = second;
        second = nxt;
    }
    let first = head;
    while (prev) {
        const n1 = first.next;
        const n2 = prev.next;
        first.next = prev;
        prev.next = n1;
        first = n1;
        prev = n2;
    }
};
